import { describe, expect, test } from "vitest";

import { conversationSnapshotSchema } from "../snapshots.js";

const validSnapshot = {
  id: "snap-1",
  importId: "imp-1",
  label: "Initial snapshot",
  isActive: 1,
  createdAt: "2026-03-12T10:00:00Z",
  updatedAt: "2026-03-12T10:00:00Z",
};

describe("conversationSnapshotSchema", () => {
  test("validates a complete valid snapshot", () => {
    const result = conversationSnapshotSchema.safeParse(validSnapshot);
    expect(result.success).toBe(true);
    if (result.success) {
      expect(result.data).toEqual(validSnapshot);
    }
  });

  test("rejects snapshot without importId", () => {
    const { importId, ...withoutImportId } = validSnapshot;
    const result = conversationSnapshotSchema.safeParse(withoutImportId);
    expect(result.success).toBe(false);
  });

  test("rejects snapshot with invalid isActive value", () => {
    const result = conversationSnapshotSchema.safeParse({
      ...validSnapshot,
      isActive: 2,
    });
    expect(result.success).toBe(false);
  });

  test("does NOT include conversationJson in schema", () => {
    const result = conversationSnapshotSchema.safeParse({
      ...validSnapshot,
      conversationJson: '{"title":"test"}',
    });
    // Should succeed but strip the extra field
    expect(result.success).toBe(true);
    if (result.success) {
      expect("conversationJson" in result.data).toBe(false);
    }
  });
});

