    const importId = `test-import-${Date.now()}`;
    const now = new Date().toISOString();

    rawDb
      .prepare(
        `INSERT INTO imports (id, source_url, source_platform, mode, status, current_stage, created_at, updated_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
      )
      .run(importId, "https://example.com", "chatgpt", "full", "done", "complete", now, now);

    const snapshotId = `test-snapshot-${Date.now()}`;
    const conversationJson = JSON.stringify({ messages: [{ role: "user", content: "hello" }] });

    // Act — insert snapshot via Drizzle
    db.insert(conversationSnapshots)
      .values({
        id: snapshotId,
        importId,
        label: "Original",
        conversationJson,
        isActive: "1",
        createdAt: now,
        updatedAt: now,
      })
      .run();

    // Assert — query back and verify
    const rows = db
      .select()
      .from(conversationSnapshots)
      .where(eq(conversationSnapshots.id, snapshotId))
      .all();

    expect(rows).toHaveLength(1);
    expect(rows[0].importId).toBe(importId);
    expect(rows[0].label).toBe("Original");
    expect(rows[0].conversationJson).toBe(conversationJson);
    expect(rows[0].isActive).toBe("1");
    expect(rows[0].createdAt).toBe(now);
    expect(rows[0].updatedAt).toBe(now);
  });

  test("isActive defaults to '0' when not provided", () => {
    // Arrange
    const importId = `test-import-default-${Date.now()}`;
    const now = new Date().toISOString();

    rawDb
      .prepare(
        `INSERT INTO imports (id, source_url, source_platform, mode, status, current_stage, created_at, updated_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
      )
      .run(importId, "https://example.com", "chatgpt", "full", "done", "complete", now, now);

    const snapshotId = `test-snapshot-default-${Date.now()}`;

    // Act — insert without isActive
    db.insert(conversationSnapshots)
      .values({
        id: snapshotId,
        importId,
        label: "Auto",
        conversationJson: "{}",
        createdAt: now,
        updatedAt: now,
      })
      .run();

    // Assert
    const rows = db
      .select()
      .from(conversationSnapshots)
      .where(eq(conversationSnapshots.id, snapshotId))
      .all();

    expect(rows).toHaveLength(1);
    expect(rows[0].isActive).toBe("0");
  });

  test("cascade deletes snapshots when import is deleted", () => {
    // Arrange
    const importId = `test-import-cascade-${Date.now()}`;
    const now = new Date().toISOString();

    rawDb
      .prepare(
        `INSERT INTO imports (id, source_url, source_platform, mode, status, current_stage, created_at, updated_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
      )
      .run(importId, "https://example.com", "chatgpt", "full", "done", "complete", now, now);

    const snapshotId = `test-snapshot-cascade-${Date.now()}`;
    db.insert(conversationSnapshots)
      .values({
        id: snapshotId,
        importId,
        label: "Will be deleted",
        conversationJson: "{}",
        isActive: "0",
        createdAt: now,
        updatedAt: now,
      })
      .run();

    // Act — delete parent import
    rawDb.prepare("DELETE FROM imports WHERE id = ?").run(importId);

    // Assert — snapshot should be gone
    const rows = db
      .select()
      .from(conversationSnapshots)
      .where(eq(conversationSnapshots.id, snapshotId))
      .all();

    expect(rows).toHaveLength(0);
  });
});

