245→        return reloaded;
246→      });
247→
248→      const activeRules = listFormatRules(
249→        detail.session.importId,
250→        detail.session.targetFormat,
251→      ).filter((rule: { status: string }) => rule.status === "active");
252→
253→      // Phase 2 — no wrapper: async AI call
254→      try {
255→        const job = getImportJob(detail.session.importId);
256→        const result = await runAgentTurn({
257→          sessionDetail: latestDetail,
258→          activeRules,
259→          job,
260→          callbacks: {
261→            onCreateRule: async ({ selector, effect, description }) => {
262→              const rule = createFormatRuleDirect({
263→                importId: latestDetail.session.importId,
264→                targetFormat: latestDetail.session.targetFormat,
265→                selector,
266→                effect: {
267→                  type: "custom_style" as const,
268→                  ...effect,
269→                  description,
270→                },
271→                instruction: description,
272→                sourceSessionId: input.sessionId,
273→              });
274→              return { ruleId: rule.id };
275→            },
276→            onUpdateRule: async ({ ruleId, effect, description }) => {
277→              updateFormatRuleEffect(
278→                ruleId,
279→                { type: "custom_style" as const, ...effect, description },
280→                description,
281→              );
282→            },
283→            onDeleteRule: async (ruleId) => {
284→              disableFormatRule(ruleId, latestDetail.session.importId);
285→            },
286→          },
287→        });
288→
289→        // Phase 3 — persist assistant message + events
290→        withTransaction(() => {
291→          appendAdjustmentMessage(
292→            input.sessionId,
293→            "assistant",
294→            result.assistantMessage,
295→          );
296→
297→          for (const action of result.actions) {
298→            recordAdjustmentEvent({
299→              importId: latestDetail.session.importId,
300→              ruleId: action.ruleId,
301→              sessionId: input.sessionId,
302→              targetFormat: latestDetail.session.targetFormat,
303→              type:
304→                action.type === "deleted" ? "rule_disabled" : "rule_applied",
305→            });
306→          }
307→
308→          if (result.actions.length > 0) {
309→            markSessionApplied(input.sessionId);
310→          } else {
311→            recordAdjustmentEvent({
312→              importId: latestDetail.session.importId,
313→              sessionId: input.sessionId,
314→              targetFormat: latestDetail.session.targetFormat,
315→              type: "clarification_requested",
316→            });
317→          }
318→        });
319→      } catch (error) {
320→        if (error instanceof AgentUnavailableError) {
321→          throw new ORPCError("SERVICE_UNAVAILABLE", {
322→            message: error.message,
323→          });
324→        }
325→        if (error instanceof DOMException && error.name === "TimeoutError") {
326→          throw new ORPCError("GATEWAY_TIMEOUT", {
327→            message: "Die KI hat zu lange gebraucht. Bitte versuche es erneut.",
328→          });
329→        }
330→        throw new ORPCError("BAD_REQUEST", {
331→          message:
332→            error instanceof Error
333→              ? error.message
334→              : "Die Live-KI-Nachricht konnte nicht verarbeitet werden.",
335→        });
336→      }
337→
338→      const nextDetail = getAdjustmentSessionDetail(input.sessionId);
339→
340→      if (!nextDetail) {
341→        throw new ORPCError("INTERNAL_SERVER_ERROR", {
342→          message: "Anpassungssession konnte nicht neu geladen werden.",
343→        });
344→      }
345→
346→      return nextDetail;
347→    }),
348→
349→    discard: os.adjustments.discard.handler(({ input }) => {
350→      try {
351→        return discardAdjustmentSession(input.sessionId);
352→      } catch (error) {
353→        throw new ORPCError("BAD_REQUEST", {
354→          message:
355→            error instanceof Error
