  1→import type {
  2→  Conversation,
  3→  ImportArtifacts,
  4→  ImportJob,
  5→  ImportListRequest,
  6→  ImportSummary,
  7→} from "@chat-exporter/shared";
  8→import { importJobSchema, importSummarySchema } from "@chat-exporter/shared";
  9→import { and, asc, desc, eq, like, or } from "drizzle-orm";
 10→
 11→import { db } from "../db/client.js";
 12→import type { Import } from "../db/schema.js";
 13→import { importSnapshots, imports } from "../db/schema.js";
 14→
 15→function serializeImport(job: ImportJob) {
 16→  return {
 17→    id: job.id,
 18→    sourceUrl: job.sourceUrl,
 19→    sourcePlatform: job.sourcePlatform,
 20→    mode: job.mode,
 21→    status: job.status,
 22→    currentStage: job.currentStage,
 23→    createdAt: job.createdAt,
 24→    updatedAt: job.updatedAt,
 25→    warningsJson: JSON.stringify(job.warnings),
 26→    error: job.error ?? null,
 27→    errorStage: job.errorStage ?? null,
 28→    summaryJson: job.summary ? JSON.stringify(job.summary) : null,
 29→    conversationJson: job.conversation
 30→      ? JSON.stringify(job.conversation)
 31→      : null,
 32→    artifactsJson: job.artifacts ? JSON.stringify(job.artifacts) : null,
 33→  };
 34→}
 35→
 36→function parseJson<T>(value: string | null): T | undefined {
 37→  if (!value) {
 38→    return undefined;
 39→  }
 40→
 41→  return JSON.parse(value) as T;
 42→}
 43→
 44→function deserializeImport(row: Import) {
 45→  return importJobSchema.parse({
 46→    id: row.id,
 47→    sourceUrl: row.sourceUrl,
 48→    sourcePlatform: row.sourcePlatform,
 49→    mode: row.mode,
 50→    status: row.status,
 51→    currentStage: row.currentStage,
 52→    createdAt: row.createdAt,
 53→    updatedAt: row.updatedAt,
 54→    warnings: parseJson<string[]>(row.warningsJson) ?? [],
 55→    error: row.error ?? undefined,
 56→    errorStage: row.errorStage ?? undefined,
 57→    summary: parseJson<ImportJob["summary"]>(row.summaryJson),
 58→    conversation: parseJson<Conversation>(row.conversationJson),
 59→    artifacts: parseJson<ImportArtifacts>(row.artifactsJson),
 60→  });
 61→}
 62→
 63→export function insertImport(job: ImportJob) {
 64→  db.insert(imports).values(serializeImport(job)).run();
 65→}
 66→
 67→export function replaceImport(job: ImportJob) {
 68→  const data = serializeImport(job);
 69→  const { id: _id, ...fields } = data;
 70→  db.update(imports).set(fields).where(eq(imports.id, job.id)).run();
 71→}
 72→
 73→export function getPersistedImport(id: string) {
 74→  const row = db.select().from(imports).where(eq(imports.id, id)).get();
 75→  return row ? deserializeImport(row) : undefined;
 76→}
 77→
 78→export function listPersistedImports() {
 79→  return db
 80→    .select()
 81→    .from(imports)
 82→    .orderBy(desc(imports.createdAt))
 83→    .all()
 84→    .map(deserializeImport);
 85→}
 86→
 87→export function saveImportSnapshot(input: {
 88→  importId: string;
 89→  sourceUrl: string;
 90→  finalUrl: string;
 91→  fetchedAt: string;
 92→  pageTitle: string;
 93→  rawHtml: string;
 94→  normalizedPayload: unknown;
 95→  fetchMetadata: Record<string, unknown>;
 96→}) {
 97→  const data = {
 98→    importId: input.importId,
 99→    sourceUrl: input.sourceUrl,
100→    finalUrl: input.finalUrl,
101→    fetchedAt: input.fetchedAt,
102→    pageTitle: input.pageTitle,
103→    rawHtml: input.rawHtml,
104→    normalizedPayloadJson: JSON.stringify(input.normalizedPayload),
105→    fetchMetadataJson: JSON.stringify(input.fetchMetadata),
106→    updatedAt: input.fetchedAt,
107→  };
108→
109→  db.insert(importSnapshots)
110→    .values(data)
111→    .onConflictDoUpdate({
112→      target: importSnapshots.importId,
113→      set: {
114→        sourceUrl: data.sourceUrl,
115→        finalUrl: data.finalUrl,
116→        fetchedAt: data.fetchedAt,
117→        pageTitle: data.pageTitle,
118→        rawHtml: data.rawHtml,
119→        normalizedPayloadJson: data.normalizedPayloadJson,
120→        fetchMetadataJson: data.fetchMetadataJson,
121→        updatedAt: data.updatedAt,
122→      },
123→    })
124→    .run();
125→}
126→
127→export function listImportSummaries(
128→  params?: Partial<ImportListRequest>,
129→): ImportSummary[] {
130→  const sortBy = params?.sortBy ?? "createdAt";
131→  const sortOrder = params?.sortOrder ?? "desc";
132→
133→  const columnMap = {
134→    createdAt: imports.createdAt,
135→    updatedAt: imports.updatedAt,
136→    sourcePlatform: imports.sourcePlatform,
137→    status: imports.status,
138→  } as const;
139→
140→  const orderColumn = columnMap[sortBy];
141→  const orderFn = sortOrder === "asc" ? asc : desc;
142→
143→  let query = db
144→    .select({
145→      id: imports.id,
146→      sourceUrl: imports.sourceUrl,
147→      sourcePlatform: imports.sourcePlatform,
148→      mode: imports.mode,
149→      status: imports.status,
150→      currentStage: imports.currentStage,
151→      createdAt: imports.createdAt,
152→      updatedAt: imports.updatedAt,
153→      warningsJson: imports.warningsJson,
154→      error: imports.error,
155→      summaryJson: imports.summaryJson,
156→      pageTitle: importSnapshots.pageTitle,
157→    })
158→    .from(imports)
159→    .leftJoin(importSnapshots, eq(imports.id, importSnapshots.importId))
160→    .orderBy(orderFn(orderColumn))
161→    .$dynamic();
162→
163→  const conditions = [];
164→
165→  if (params?.status) {
166→    conditions.push(eq(imports.status, params.status));
167→  }
168→
169→  if (params?.platform) {
170→    conditions.push(eq(imports.sourcePlatform, params.platform));
171→  }
172→
173→  if (params?.search) {
174→    const pattern = `%${params.search}%`;
175→    conditions.push(
176→      or(
177→        like(imports.sourceUrl, pattern),
178→        like(importSnapshots.pageTitle, pattern),
179→      ),
180→    );
181→  }
182→
183→  if (conditions.length > 0) {
184→    query = query.where(and(...conditions));
185→  }
186→
187→  return query.all().map((row) =>
188→    importSummarySchema.parse({
189→      id: row.id,
190→      sourceUrl: row.sourceUrl,
191→      sourcePlatform: row.sourcePlatform,
192→      mode: row.mode,
193→      status: row.status,
194→      currentStage: row.currentStage,
195→      createdAt: row.createdAt,
196→      updatedAt: row.updatedAt,
197→      warnings: parseJson<string[]>(row.warningsJson) ?? [],
198→      error: row.error ?? undefined,
199→      summary: parseJson<ImportJob["summary"]>(row.summaryJson),
200→      pageTitle: row.pageTitle ?? undefined,
201→    }),
202→  );
203→}
204→
205→export function deleteImport(id: string): boolean {
206→  const result = db.delete(imports).where(eq(imports.id, id)).run();
207→  return result.changes > 0;
208→}
209→
210→export function getPersistedImportSnapshot(importId: string) {
211→  const row = db
212→    .select()
213→    .from(importSnapshots)
214→    .where(eq(importSnapshots.importId, importId))
215→    .get();
216→
217→  if (!row) {
218→    return undefined;
219→  }
220→
221→  return {
222→    importId: row.importId,
223→    sourceUrl: row.sourceUrl,
224→    finalUrl: row.finalUrl,
225→    fetchedAt: row.fetchedAt,
