import type { ConversationSnapshot } from "@chat-exporter/shared";
import { afterEach, describe, expect, test } from "vitest";

import { db } from "../db/client.js";
import { conversationSnapshots, imports } from "../db/schema.js";
import { eq } from "drizzle-orm";

import {
  activateSnapshot,
  createSnapshot,
  deactivateAllSnapshots,
  deleteSnapshot,
  getActiveSnapshot,
  getSnapshot,
  listSnapshots,
  renameSnapshot,
  updateSnapshotContent,
} from "./snapshot-repository.js";

const createdImportIds: string[] = [];

function createTestImport(): string {
  const id = crypto.randomUUID();
  db.insert(imports)
    .values({
      id,
      sourceUrl: "https://example.com",
      sourcePlatform: "chatgpt",
      mode: "archive",
      status: "completed",
      currentStage: "done",
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    })
    .run();
  createdImportIds.push(id);
  return id;
}

afterEach(() => {
  for (const id of createdImportIds) {
    db.delete(imports).where(eq(imports.id, id)).run();
  }
  createdImportIds.length = 0;
});

describe("snapshot-repository", () => {
  test("createSnapshot creates a new snapshot with correct fields", () => {
    const importId = createTestImport();
    const json = JSON.stringify({ messages: [] });

    const result = createSnapshot(importId, "Test Label", json);

    expect(result.id).toBeDefined();
    expect(result.importId).toBe(importId);
    expect(result.label).toBe("Test Label");
    expect(result.isActive).toBe(0);
    expect(result.createdAt).toBeDefined();
    expect(result.updatedAt).toBeDefined();
    expect((result as Record<string, unknown>).conversationJson).toBeUndefined();
  });

  test("listSnapshots returns metadata without conversationJson", () => {
    const importId = createTestImport();
    createSnapshot(importId, "Snap 1", JSON.stringify({ a: 1 }));
    createSnapshot(importId, "Snap 2", JSON.stringify({ b: 2 }));

    const list = listSnapshots(importId);

    expect(list).toHaveLength(2);
    for (const snap of list) {
      expect(snap.importId).toBe(importId);
      expect(snap.isActive).toBe(0);
      expect((snap as Record<string, unknown>).conversationJson).toBeUndefined();
    }
    const labels = list.map((s) => s.label);
    expect(labels).toContain("Snap 1");
    expect(labels).toContain("Snap 2");
  });

  test("getSnapshot returns full snapshot with conversationJson", () => {
    const importId = createTestImport();
    const json = JSON.stringify({ messages: [{ role: "user" }] });
    const created = createSnapshot(importId, "Full", json);

    const result = getSnapshot(created.id);

    expect(result).not.toBeNull();
    expect(result!.id).toBe(created.id);
    expect(result!.conversationJson).toBe(json);
    expect(result!.isActive).toBe(0);
  });

  test("getSnapshot returns null for non-existent id", () => {
    const result = getSnapshot("non-existent-id");
    expect(result).toBeNull();
  });

  test("getActiveSnapshot returns null when no snapshot is active", () => {
    const importId = createTestImport();
    createSnapshot(importId, "Inactive", JSON.stringify({}));

    const result = getActiveSnapshot(importId);

    expect(result).toBeNull();
  });

  test("activateSnapshot sets isActive=1 and deactivates others", () => {
    const importId = createTestImport();
    const snap1 = createSnapshot(importId, "First", JSON.stringify({ v: 1 }));
    const snap2 = createSnapshot(importId, "Second", JSON.stringify({ v: 2 }));

    // Activate first
    activateSnapshot(snap1.id);

    // Activate second — first should be deactivated
    const result = activateSnapshot(snap2.id);

    expect(result.isActive).toBe(1);

    const active = getActiveSnapshot(importId);
    expect(active).not.toBeNull();
    expect(active!.id).toBe(snap2.id);

    const first = getSnapshot(snap1.id);
    expect(first!.isActive).toBe(0);
  });

  test("deactivateAllSnapshots sets all snapshots to isActive=0", () => {
    const importId = createTestImport();
    const snap1 = createSnapshot(importId, "A", JSON.stringify({}));
    activateSnapshot(snap1.id);

    deactivateAllSnapshots(importId);

    const list = listSnapshots(importId);
    for (const snap of list) {
      expect(snap.isActive).toBe(0);
    }
  });

  test("deleteSnapshot removes the snapshot", () => {
    const importId = createTestImport();
    const snap = createSnapshot(importId, "To Delete", JSON.stringify({}));

    const result = deleteSnapshot(snap.id);

    expect(result).toBe(true);
    expect(getSnapshot(snap.id)).toBeNull();
  });

  test("deleteSnapshot returns false for non-existent id", () => {
    const result = deleteSnapshot("non-existent-id");
    expect(result).toBe(false);
  });

  test("renameSnapshot updates the label", () => {
    const importId = createTestImport();
    const snap = createSnapshot(importId, "Old Label", JSON.stringify({}));

    const result = renameSnapshot(snap.id, "New Label");

    expect(result).not.toBeNull();
    expect(result!.label).toBe("New Label");
    expect(result!.updatedAt).not.toBe(snap.updatedAt);
  });

  test("renameSnapshot returns null for non-existent id", () => {
    const result = renameSnapshot("non-existent-id", "Label");
    expect(result).toBeNull();
  });

  test("updateSnapshotContent updates conversationJson", () => {
    const importId = createTestImport();
    const snap = createSnapshot(importId, "Content", JSON.stringify({ old: true }));
    const newJson = JSON.stringify({ new: true });

    const result = updateSnapshotContent(snap.id, newJson);

    expect(result).not.toBeNull();
    expect(result!.updatedAt).not.toBe(snap.updatedAt);

    const full = getSnapshot(snap.id);
    expect(full!.conversationJson).toBe(newJson);
  });

  test("updateSnapshotContent returns null for non-existent id", () => {
    const result = updateSnapshotContent("non-existent-id", "{}");
    expect(result).toBeNull();
  });

  test("activateSnapshot is atomic (transaction)", () => {
    const importId = createTestImport();
    const snap1 = createSnapshot(importId, "A", JSON.stringify({}));
    const snap2 = createSnapshot(importId, "B", JSON.stringify({}));

    activateSnapshot(snap1.id);
    activateSnapshot(snap2.id);

    // Only snap2 should be active; snap1 deactivated in same transaction
    const list = listSnapshots(importId);
    const activeCount = list.filter((s) => s.isActive === 1).length;
    expect(activeCount).toBe(1);

    const active = list.find((s) => s.isActive === 1);
    expect(active!.id).toBe(snap2.id);
  });
});

import type { ConversationSnapshot } from "@chat-exporter/shared";
import { eq, and } from "drizzle-orm";

import { db, withTransaction } from "../db/client.js";
import {
  conversationSnapshots,
  type ConversationSnapshotRecord,
} from "../db/schema.js";

function toSnapshot(row: ConversationSnapshotRecord): ConversationSnapshot {
  return {
    id: row.id,
    importId: row.importId,
    label: row.label,
    isActive: row.isActive === "1" ? 1 : 0,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt,
  };
}

export function createSnapshot(
  importId: string,
  label: string,
  conversationJson: string,
): ConversationSnapshot {
  const id = crypto.randomUUID();
  const now = new Date().toISOString();

  db.insert(conversationSnapshots)
    .values({
      id,
      importId,
      label,
      conversationJson,
      isActive: "0",
      createdAt: now,
      updatedAt: now,
    })
    .run();

  return {
    id,
    importId,
    label,
    isActive: 0,
    createdAt: now,
    updatedAt: now,
  };
}

export function listSnapshots(importId: string): ConversationSnapshot[] {
  const rows = db
    .select({
      id: conversationSnapshots.id,
      importId: conversationSnapshots.importId,
      label: conversationSnapshots.label,
      isActive: conversationSnapshots.isActive,
      createdAt: conversationSnapshots.createdAt,
      updatedAt: conversationSnapshots.updatedAt,
    })
    .from(conversationSnapshots)
    .where(eq(conversationSnapshots.importId, importId))
    .all();

  return rows.map(toSnapshot);
}

export function getSnapshot(
  snapshotId: string,
): (ConversationSnapshot & { conversationJson: string }) | null {
  const row = db
    .select()
    .from(conversationSnapshots)
    .where(eq(conversationSnapshots.id, snapshotId))
    .get();

  if (!row) return null;

  return {
    ...toSnapshot(row),
    conversationJson: row.conversationJson,
  };
}

export function getActiveSnapshot(
  importId: string,
): (ConversationSnapshot & { conversationJson: string }) | null {
  const row = db
    .select()
    .from(conversationSnapshots)
    .where(
      and(
        eq(conversationSnapshots.importId, importId),
        eq(conversationSnapshots.isActive, "1"),
      ),
    )
    .get();

  if (!row) return null;

  return {
    ...toSnapshot(row),
    conversationJson: row.conversationJson,
  };
}

export function activateSnapshot(snapshotId: string): ConversationSnapshot {
  return withTransaction(() => {
    const row = db
      .select()
      .from(conversationSnapshots)
      .where(eq(conversationSnapshots.id, snapshotId))
      .get();

    if (!row) {
      throw new Error(`Snapshot not found: ${snapshotId}`);
    }

    const now = new Date().toISOString();

    // Deactivate all snapshots for the same import
    db.update(conversationSnapshots)
      .set({ isActive: "0", updatedAt: now })
      .where(eq(conversationSnapshots.importId, row.importId))
      .run();

    // Activate this snapshot
    db.update(conversationSnapshots)
      .set({ isActive: "1", updatedAt: now })
      .where(eq(conversationSnapshots.id, snapshotId))
      .run();

    return {
      ...toSnapshot(row),
      isActive: 1,
      updatedAt: now,
    };
  });
}

export function deactivateAllSnapshots(importId: string): void {
  const now = new Date().toISOString();
  db.update(conversationSnapshots)
    .set({ isActive: "0", updatedAt: now })
    .where(eq(conversationSnapshots.importId, importId))
    .run();
}

export function deleteSnapshot(snapshotId: string): boolean {
  const result = db
    .delete(conversationSnapshots)
    .where(eq(conversationSnapshots.id, snapshotId))
    .run();
  return result.changes > 0;
}

export function renameSnapshot(
  snapshotId: string,
  label: string,
): ConversationSnapshot | null {
  const now = new Date().toISOString();

  const result = db
    .update(conversationSnapshots)
    .set({ label, updatedAt: now })
    .where(eq(conversationSnapshots.id, snapshotId))
    .run();

  if (result.changes === 0) return null;

  const row = db
    .select()
    .from(conversationSnapshots)
    .where(eq(conversationSnapshots.id, snapshotId))
    .get();

  return row ? toSnapshot(row) : null;
}

export function updateSnapshotContent(
  snapshotId: string,
  conversationJson: string,
): ConversationSnapshot | null {
  const now = new Date().toISOString();

  const result = db
    .update(conversationSnapshots)
    .set({ conversationJson, updatedAt: now })
    .where(eq(conversationSnapshots.id, snapshotId))
    .run();

  if (result.changes === 0) return null;

  const row = db
    .select()
    .from(conversationSnapshots)
    .where(eq(conversationSnapshots.id, snapshotId))
    .get();

  return row ? toSnapshot(row) : null;
}

import { describe, expect, test } from "vitest";
import type { Block } from "@chat-exporter/shared";
import { blocksToTipTapDoc, tipTapDocToBlocks } from "../serializer";

describe("blocksToTipTapDoc", () => {
  test("converts paragraph block to TipTap paragraph node", () => {
    const blocks: Block[] = [{ type: "paragraph", text: "Hello world" }];

    const doc = blocksToTipTapDoc(blocks);

    expect(doc).toEqual({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [{ type: "text", text: "Hello world" }],
        },
      ],
    });
  });

  test("converts heading block with level to TipTap heading node", () => {
    const blocks: Block[] = [{ type: "heading", level: 3, text: "Title" }];

    const doc = blocksToTipTapDoc(blocks);

    expect(doc).toEqual({
      type: "doc",
      content: [
        {
          type: "heading",
          attrs: { level: 3 },
          content: [{ type: "text", text: "Title" }],
        },
      ],
    });
  });

  test("converts list block to TipTap bulletList node", () => {
    const blocks: Block[] = [
      { type: "list", ordered: false, items: ["Item A", "Item B"] },
    ];

    const doc = blocksToTipTapDoc(blocks);

    expect(doc).toEqual({
      type: "doc",
      content: [
        {
          type: "bulletList",
          content: [
            {
              type: "listItem",
              content: [
                {
                  type: "paragraph",
                  content: [{ type: "text", text: "Item A" }],
                },
              ],
            },
            {
              type: "listItem",
              content: [
                {
                  type: "paragraph",
                  content: [{ type: "text", text: "Item B" }],
                },
              ],
            },
          ],
        },
      ],
    });
  });

  test("converts ordered list to TipTap orderedList node", () => {
    const blocks: Block[] = [
      { type: "list", ordered: true, items: ["First", "Second"] },
    ];

    const doc = blocksToTipTapDoc(blocks);

    expect(doc.content?.[0].type).toBe("orderedList");
  });

  test("converts code block with language to TipTap codeBlock node", () => {
    const blocks: Block[] = [
      { type: "code", language: "typescript", text: "const x = 1;" },
    ];

    const doc = blocksToTipTapDoc(blocks);

    expect(doc).toEqual({
      type: "doc",
      content: [
        {
          type: "codeBlock",
          attrs: { language: "typescript" },
          content: [{ type: "text", text: "const x = 1;" }],
        },
      ],
    });
  });

  test("converts quote block to TipTap blockquote node", () => {
    const blocks: Block[] = [{ type: "quote", text: "A wise quote" }];

    const doc = blocksToTipTapDoc(blocks);

    expect(doc).toEqual({
      type: "doc",
      content: [
        {
          type: "blockquote",
          content: [
            {
              type: "paragraph",
              content: [{ type: "text", text: "A wise quote" }],
            },
          ],
        },
      ],
    });
  });

  test("converts table block to TipTap table node", () => {
    const blocks: Block[] = [
      {
        type: "table",
        headers: ["Name", "Age"],
        rows: [
          ["Alice", "30"],
          ["Bob", "25"],
        ],
      },
    ];

    const doc = blocksToTipTapDoc(blocks);

    expect(doc).toEqual({
      type: "doc",
      content: [
        {
          type: "table",
          content: [
            {
              type: "tableRow",
              content: [
                {
                  type: "tableHeader",
                  content: [
                    {
                      type: "paragraph",
                      content: [{ type: "text", text: "Name" }],
                    },
                  ],
                },
                {
                  type: "tableHeader",
                  content: [
                    {
                      type: "paragraph",
                      content: [{ type: "text", text: "Age" }],
                    },
                  ],
                },
              ],
            },
            {
              type: "tableRow",
              content: [
                {
                  type: "tableCell",
                  content: [
                    {
                      type: "paragraph",
                      content: [{ type: "text", text: "Alice" }],
                    },
                  ],
                },
                {
                  type: "tableCell",
                  content: [
                    {
                      type: "paragraph",
                      content: [{ type: "text", text: "30" }],
                    },
                  ],
                },
              ],
            },
            {
              type: "tableRow",
              content: [
                {
                  type: "tableCell",
                  content: [
                    {
                      type: "paragraph",
                      content: [{ type: "text", text: "Bob" }],
                    },
                  ],
                },
                {
                  type: "tableCell",
                  content: [
                    {
                      type: "paragraph",
                      content: [{ type: "text", text: "25" }],
                    },
                  ],
                },
              ],
            },
          ],
        },
      ],
    });
  });

  test("handles empty blocks array", () => {
    const doc = blocksToTipTapDoc([]);

    expect(doc).toEqual({ type: "doc", content: [] });
  });
});

describe("tipTapDocToBlocks", () => {
  test("converts TipTap paragraph back to paragraph block", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [{ type: "text", text: "Hello" }],
        },
      ],
    };

    const blocks = tipTapDocToBlocks(doc);

    expect(blocks).toEqual([{ type: "paragraph", text: "Hello" }]);
  });

  test("converts TipTap heading back to heading block", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "heading",
          attrs: { level: 2 },
          content: [{ type: "text", text: "Section" }],
        },
      ],
    };

    const blocks = tipTapDocToBlocks(doc);

    expect(blocks).toEqual([{ type: "heading", level: 2, text: "Section" }]);
  });

  test("converts TipTap bulletList back to list block", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "bulletList",
          content: [
            {
              type: "listItem",
              content: [
                {
                  type: "paragraph",
                  content: [{ type: "text", text: "A" }],
                },
              ],
            },
            {
              type: "listItem",
              content: [
                {
                  type: "paragraph",
                  content: [{ type: "text", text: "B" }],
                },
              ],
            },
          ],
        },
      ],
    };

    const blocks = tipTapDocToBlocks(doc);

    expect(blocks).toEqual([
      { type: "list", ordered: false, items: ["A", "B"] },
    ]);
  });

  test("converts TipTap orderedList back to ordered list block", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "orderedList",
          content: [
            {
              type: "listItem",
              content: [
                {
                  type: "paragraph",
                  content: [{ type: "text", text: "First" }],
                },
              ],
            },
          ],
        },
      ],
    };

    const blocks = tipTapDocToBlocks(doc);

    expect(blocks).toEqual([
      { type: "list", ordered: true, items: ["First"] },
    ]);
  });

  test("converts TipTap codeBlock back to code block", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "codeBlock",
          attrs: { language: "python" },
          content: [{ type: "text", text: "print('hi')" }],
        },
      ],
    };

    const blocks = tipTapDocToBlocks(doc);

    expect(blocks).toEqual([
      { type: "code", language: "python", text: "print('hi')" },
    ]);
  });

  test("converts TipTap blockquote back to quote block", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "blockquote",
          content: [
            {
              type: "paragraph",
              content: [{ type: "text", text: "Quote text" }],
            },
          ],
        },
      ],
    };

    const blocks = tipTapDocToBlocks(doc);

    expect(blocks).toEqual([{ type: "quote", text: "Quote text" }]);
  });

  test("converts TipTap table back to table block", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "table",
          content: [
            {
              type: "tableRow",
              content: [
                {
                  type: "tableHeader",
                  content: [
                    {
                      type: "paragraph",
                      content: [{ type: "text", text: "Col1" }],
                    },
                  ],
                },
              ],
            },
            {
              type: "tableRow",
              content: [
                {
                  type: "tableCell",
                  content: [
                    {
                      type: "paragraph",
                      content: [{ type: "text", text: "Val1" }],
                    },
                  ],
                },
              ],
            },
          ],
        },
      ],
    };

    const blocks = tipTapDocToBlocks(doc);

    expect(blocks).toEqual([
      { type: "table", headers: ["Col1"], rows: [["Val1"]] },
    ]);
  });

  test("handles empty doc", () => {
    const blocks = tipTapDocToBlocks({ type: "doc" });

    expect(blocks).toEqual([]);
  });
});

describe("Roundtrip", () => {
  test("paragraph roundtrip is lossless", () => {
    const blocks: Block[] = [{ type: "paragraph", text: "Hello world" }];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("heading with level roundtrip is lossless", () => {
    const blocks: Block[] = [
      { type: "heading", level: 4, text: "Deep heading" },
    ];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("unordered list roundtrip is lossless", () => {
    const blocks: Block[] = [
      { type: "list", ordered: false, items: ["X", "Y", "Z"] },
    ];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("ordered list roundtrip is lossless", () => {
    const blocks: Block[] = [
      { type: "list", ordered: true, items: ["One", "Two"] },
    ];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("code block roundtrip is lossless", () => {
    const blocks: Block[] = [
      { type: "code", language: "rust", text: 'fn main() {\n    println!("hi");\n}' },
    ];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("quote roundtrip is lossless", () => {
    const blocks: Block[] = [{ type: "quote", text: "To be or not to be" }];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("table roundtrip is lossless", () => {
    const blocks: Block[] = [
      {
        type: "table",
        headers: ["A", "B"],
        rows: [
          ["1", "2"],
          ["3", "4"],
        ],
      },
    ];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("mixed block array roundtrip is lossless", () => {
    const blocks: Block[] = [
      { type: "heading", level: 1, text: "Title" },
      { type: "paragraph", text: "Intro paragraph" },
      { type: "list", ordered: false, items: ["a", "b"] },
      { type: "code", language: "js", text: "console.log(1)" },
      { type: "quote", text: "Famous words" },
      {
        type: "table",
        headers: ["Key", "Value"],
        rows: [["foo", "bar"]],
      },
    ];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("empty blocks roundtrip", () => {
    const blocks: Block[] = [];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("block with special characters (umlauts, emojis)", () => {
    const blocks: Block[] = [
      { type: "paragraph", text: "Über die Brücke gehen 🌉 — äöüß" },
      { type: "heading", level: 2, text: "Ähre & Würde 🎩" },
    ];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });

  test("code block preserves whitespace and indentation", () => {
    const blocks: Block[] = [
      {
        type: "code",
        language: "python",
        text: "def foo():\n    if True:\n        return 42\n    return 0",
      },
    ];

    expect(tipTapDocToBlocks(blocksToTipTapDoc(blocks))).toEqual(blocks);
  });
});

