## Task: Implement Step 6 — Serializer: Blocks ↔ TipTap

Follow strict TDD: write failing tests first, then implement, then refactor.
Commit your changes atomically when tests pass (stage files by name, never `git add .`).

### Context

Frontend app at `apps/web/`. TipTap is already installed (v3.x via @tiptap/starter-kit, @tiptap/extension-table).

**Block types** from `@chat-exporter/shared` (`packages/shared/src/conversation.ts`):
```ts
// Block is a discriminated union on "type":
type Block = 
  | { type: "paragraph"; text: string }
  | { type: "heading"; level: 1|2|3|4|5|6; text: string }
  | { type: "list"; ordered: boolean; items: string[] }
  | { type: "code"; language: string; text: string }
  | { type: "quote"; text: string }
  | { type: "table"; headers: string[]; rows: string[][] }
```

**TipTap JSONContent** structure (from @tiptap/core):
```ts
interface JSONContent {
  type: string;
  attrs?: Record<string, any>;
  content?: JSONContent[];
  text?: string;
  marks?: { type: string; attrs?: Record<string, any> }[];
}
```

**TipTap node types mapping:**
- paragraph → `{ type: "paragraph", content: [{ type: "text", text: "..." }] }`
- heading → `{ type: "heading", attrs: { level: N }, content: [{ type: "text", text: "..." }] }`
- list (ordered=false) → `{ type: "bulletList", content: [{ type: "listItem", content: [{ type: "paragraph", content: [{ type: "text", text: "..." }] }] }] }`
- list (ordered=true) → `{ type: "orderedList", content: [{ type: "listItem", ... }] }`
- code → `{ type: "codeBlock", attrs: { language: "ts" }, content: [{ type: "text", text: "..." }] }`
- quote → `{ type: "blockquote", content: [{ type: "paragraph", content: [{ type: "text", text: "..." }] }] }`
- table → `{ type: "table", content: [{ type: "tableRow", content: [{ type: "tableHeader"|"tableCell", content: [...] }] }] }`

### What to implement

Create `apps/web/src/components/format-workspace/tiptap/serializer.ts`:

```ts
import type { Block } from "@chat-exporter/shared";

interface JSONContent {
  type: string;
  attrs?: Record<string, any>;
  content?: JSONContent[];
  text?: string;
  marks?: { type: string; attrs?: Record<string, any> }[];
}

/**
 * Convert Block array to TipTap document JSON.
 * Effects parameter is reserved for future use (Step 13).
 */
export function blocksToTipTapDoc(blocks: Block[], effects?: unknown[]): JSONContent {
  return {
    type: "doc",
    content: blocks.map(blockToNode),
  };
}

function blockToNode(block: Block): JSONContent {
  switch (block.type) {
    case "paragraph":
      return { type: "paragraph", content: textContent(block.text) };
    case "heading":
      return { type: "heading", attrs: { level: block.level }, content: textContent(block.text) };
    case "list":
      return {
        type: block.ordered ? "orderedList" : "bulletList",
        content: block.items.map(item => ({
          type: "listItem",
          content: [{ type: "paragraph", content: textContent(item) }],
        })),
      };
    case "code":
      return { type: "codeBlock", attrs: { language: block.language }, content: textContent(block.text) };
    case "quote":
      return { type: "blockquote", content: [{ type: "paragraph", content: textContent(block.text) }] };
    case "table":
      return tableToNode(block);
  }
}

function textContent(text: string): JSONContent[] {
  if (!text) return [];
  return [{ type: "text", text }];
}

function tableToNode(block: { headers: string[]; rows: string[][] }): JSONContent {
  const headerRow: JSONContent = {
    type: "tableRow",
    content: block.headers.map(h => ({
      type: "tableHeader",
      content: [{ type: "paragraph", content: textContent(h) }],
    })),
  };
  const dataRows = block.rows.map(row => ({
    type: "tableRow",
    content: row.map(cell => ({
      type: "tableCell",
      content: [{ type: "paragraph", content: textContent(cell) }],
    })),
  }));
  return { type: "table", content: [headerRow, ...dataRows] };
}

/**
 * Convert TipTap document JSON back to Block array.
 */
export function tipTapDocToBlocks(doc: JSONContent): Block[] {
  if (!doc.content) return [];
  return doc.content.map(nodeToBlock).filter((b): b is Block => b !== null);
}

function nodeToBlock(node: JSONContent): Block | null {
  switch (node.type) {
    case "paragraph":
      return { type: "paragraph", text: extractText(node) };
    case "heading":
      return { type: "heading", level: node.attrs?.level ?? 1, text: extractText(node) };
    case "bulletList":
      return { type: "list", ordered: false, items: extractListItems(node) };
    case "orderedList":
      return { type: "list", ordered: true, items: extractListItems(node) };
    case "codeBlock":
      return { type: "code", language: node.attrs?.language ?? "text", text: extractText(node) };
    case "blockquote":
      return { type: "quote", text: extractNestedText(node) };
    case "table":
      return tableNodeToBlock(node);
    default:
      return null;
  }
}

function extractText(node: JSONContent): string {
  if (!node.content) return "";
  return node.content.map(c => c.text ?? "").join("");
}

function extractNestedText(node: JSONContent): string {
  if (!node.content) return "";
  return node.content.map(child => extractText(child)).join("\n");
}

function extractListItems(node: JSONContent): string[] {
  if (!node.content) return [];
  return node.content.map(listItem => {
    if (!listItem.content) return "";
    // listItem contains paragraph(s)
    return listItem.content.map(p => extractText(p)).join("\n");
  });
}

function tableNodeToBlock(node: JSONContent): Block {
  if (!node.content || node.content.length === 0) {
    return { type: "table", headers: [], rows: [] };
  }
  const [headerRow, ...dataRows] = node.content;
  const headers = (headerRow?.content ?? []).map(cell => extractNestedText(cell));
  const rows = dataRows.map(row => (row.content ?? []).map(cell => extractNestedText(cell)));
  return { type: "table", headers, rows };
}
```

