```ts
describe("blocksToTipTapDoc", () => {
  test("converts paragraph block to TipTap paragraph node")
  test("converts heading block with level to TipTap heading node")
  test("converts list block to TipTap bulletList node")
  test("converts ordered list to TipTap orderedList node")
  test("converts code block with language to TipTap codeBlock node")
  test("converts quote block to TipTap blockquote node")
  test("converts table block to TipTap table node")
  test("handles empty blocks array")
});

describe("tipTapDocToBlocks", () => {
  test("converts TipTap paragraph back to paragraph block")
  test("converts TipTap heading back to heading block")
  test("converts TipTap bulletList back to list block")
  test("converts TipTap orderedList back to ordered list block")
  test("converts TipTap codeBlock back to code block")
  test("converts TipTap blockquote back to quote block")
  test("converts TipTap table back to table block")
  test("handles empty doc")
});

describe("Roundtrip", () => {
  test("paragraph roundtrip is lossless")
  test("heading with level roundtrip is lossless")
  test("unordered list roundtrip is lossless")
  test("ordered list roundtrip is lossless")
  test("code block roundtrip is lossless")
  test("quote roundtrip is lossless")
  test("table roundtrip is lossless")
  test("mixed block array roundtrip is lossless")
  test("empty blocks roundtrip")
  test("block with special characters (umlauts, emojis)")
  test("code block preserves whitespace and indentation")
});
