  9→
 10→function toSnapshot(
 11→  row: Omit<ConversationSnapshotRecord, "conversationJson">,
 12→): ConversationSnapshot {
 13→  return {
 14→    id: row.id,
 15→    importId: row.importId,
 16→    label: row.label,
 17→    isActive: row.isActive === "1" ? 1 : 0,
 18→    createdAt: row.createdAt,
 19→    updatedAt: row.updatedAt,
 20→  };
 21→}
 22→
 23→export function createSnapshot(
 24→  importId: string,
 25→  label: string,
 26→  conversationJson: string,
 27→): ConversationSnapshot {
 28→  const id = crypto.randomUUID();
 29→  const now = new Date().toISOString();
 30→
 31→  db.insert(conversationSnapshots)
 32→    .values({
 33→      id,
 34→      importId,
 35→      label,
 36→      conversationJson,
 37→      isActive: "0",
 38→      createdAt: now,
 39→      updatedAt: now,
 40→    })
 41→    .run();
 42→
 43→  return {
 44→    id,
 45→    importId,
 46→    label,
 47→    isActive: 0,
 48→    createdAt: now,
 49→    updatedAt: now,
 50→  };
 51→}
 52→
 53→export function listSnapshots(importId: string): ConversationSnapshot[] {
 54→  const rows = db
 55→    .select({
 56→      id: conversationSnapshots.id,
 57→      importId: conversationSnapshots.importId,
 58→      label: conversationSnapshots.label,
 59→      isActive: conversationSnapshots.isActive,
 60→      createdAt: conversationSnapshots.createdAt,
 61→      updatedAt: conversationSnapshots.updatedAt,
 62→    })
 63→    .from(conversationSnapshots)
 64→    .where(eq(conversationSnapshots.importId, importId))
 65→    .all();
 66→
 67→  return rows.map(toSnapshot);
 68→}
 69→
 70→export function getSnapshot(
 71→  snapshotId: string,
 72→): (ConversationSnapshot & { conversationJson: string }) | null {
 73→  const row = db
 74→    .select()
 75→    .from(conversationSnapshots)
 76→    .where(eq(conversationSnapshots.id, snapshotId))
 77→    .get();
 78→
 79→  if (!row) return null;
 80→
 81→  return {
 82→    ...toSnapshot(row),
 83→    conversationJson: row.conversationJson,
 84→  };
 85→}
 86→
 87→export function getActiveSnapshot(
 88→  importId: string,
 89→): (ConversationSnapshot & { conversationJson: string }) | null {
 90→  const row = db
 91→    .select()
 92→    .from(conversationSnapshots)
 93→    .where(
 94→      and(
 95→        eq(conversationSnapshots.importId, importId),
 96→        eq(conversationSnapshots.isActive, "1"),
 97→      ),
 98→    )
 99→    .get();
100→
101→  if (!row) return null;
102→
103→  return {
104→    ...toSnapshot(row),
105→    conversationJson: row.conversationJson,
106→  };
107→}
