109→export function activateSnapshot(snapshotId: string): ConversationSnapshot {
110→  return withTransaction(() => {
111→    const row = db
112→      .select()
113→      .from(conversationSnapshots)
114→      .where(eq(conversationSnapshots.id, snapshotId))
115→      .get();
116→
117→    if (!row) {
118→      throw new Error(`Snapshot not found: ${snapshotId}`);
119→    }
120→
121→    const now = new Date().toISOString();
122→
123→    // Deactivate all snapshots for the same import
124→    db.update(conversationSnapshots)
125→      .set({ isActive: "0", updatedAt: now })
126→      .where(eq(conversationSnapshots.importId, row.importId))
127→      .run();
128→
129→    // Activate this snapshot
130→    db.update(conversationSnapshots)
131→      .set({ isActive: "1", updatedAt: now })
132→      .where(eq(conversationSnapshots.id, snapshotId))
133→      .run();
134→
135→    return {
136→      ...toSnapshot(row),
137→      isActive: 1,
138→      updatedAt: now,
139→    };
140→  });
141→}
