```

### What to implement

Create `apps/web/src/components/format-workspace/tiptap/turn-editor.tsx`:

```tsx
import { useCallback, useEffect, useRef } from "react";
import { useEditor, EditorContent } from "@tiptap/react";
import type { Block } from "@chat-exporter/shared";
import { extensions } from "./extensions";
import { blocksToTipTapDoc, tipTapDocToBlocks } from "./serializer";

interface TurnEditorProps {
  blocks: Block[];
  effects?: unknown[];
  editable: boolean;
  onContentChange?: (blocks: Block[]) => void;
}

export function TurnEditor({ blocks, effects, editable, onContentChange }: TurnEditorProps) {
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const editor = useEditor({
    extensions,
    content: blocksToTipTapDoc(blocks, effects),
    editable,
    onUpdate: ({ editor }) => {
      if (!onContentChange) return;

      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }

      debounceRef.current = setTimeout(() => {
        const updatedBlocks = tipTapDocToBlocks(editor.getJSON());
        onContentChange(updatedBlocks);
      }, 500);
    },
  });

  // Sync editable prop
  useEffect(() => {
    if (editor && editor.isEditable !== editable) {
      editor.setEditable(editable);
    }
  }, [editor, editable]);

  // Clean up debounce on unmount
  useEffect(() => {
    return () => {
      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }
    };
  }, []);

  if (!editor) {
    return null;
  }

  return (
    <div className="prose prose-sm max-w-none dark:prose-invert">
      <EditorContent editor={editor} />
    </div>
  );
}
```

Important notes:
- Import from `@tiptap/react` for `useEditor` and `EditorContent`
- Use the `extensions` bundle from `./extensions`
- Debounce `onContentChange` by 500ms
- Sync `editable` prop via `useEffect`
- Wrap in prose class for Tailwind typography styling
- This is a React.lazy()-compatible component (it's a named export, can be lazy-loaded by parent)

