  list: os.snapshots.list.handler(({ input }) => {
    return listSnapshots(input.importId);
  }),

  get: os.snapshots.get.handler(({ input }) => {
    const snapshot = getSnapshot(input.id);
    if (!snapshot) {
      throw new ORPCError("NOT_FOUND", {
        message: "Snapshot nicht gefunden.",
      });
    }
    return snapshot;
  }),

  getActive: os.snapshots.getActive.handler(({ input }) => {
    return getActiveSnapshot(input.importId);
  }),

  create: os.snapshots.create.handler(({ input }) => {
    return createSnapshot(input.importId, input.label, input.conversationJson);
  }),

  activate: os.snapshots.activate.handler(({ input }) => {
    try {
      return activateSnapshot(input.id);
    } catch {
      throw new ORPCError("NOT_FOUND", {
        message: "Snapshot nicht gefunden.",
      });
    }
  }),

  deactivate: os.snapshots.deactivate.handler(({ input }) => {
    deactivateAllSnapshots(input.importId);
    return { deactivated: true };
  }),

  delete: os.snapshots.delete.handler(({ input }) => {
    const deleted = deleteSnapshot(input.id);
    return { deleted };
  }),

  rename: os.snapshots.rename.handler(({ input }) => {
    const snapshot = renameSnapshot(input.id, input.label);
    if (!snapshot) {
      throw new ORPCError("NOT_FOUND", {
        message: "Snapshot nicht gefunden.",
      });
    }
    return snapshot;
  }),

  updateContent: os.snapshots.updateContent.handler(({ input }) => {
    const snapshot = updateSnapshotContent(input.id, input.conversationJson);
    if (!snapshot) {
      throw new ORPCError("NOT_FOUND", {
        message: "Snapshot nicht gefunden.",
      });
    }
    return snapshot;
  }),
},

