  1→import type { Block } from "@chat-exporter/shared";
  2→
  3→interface JSONContent {
  4→  type: string;
  5→  attrs?: Record<string, unknown>;
  6→  content?: JSONContent[];
  7→  text?: string;
  8→  marks?: { type: string; attrs?: Record<string, unknown> }[];
  9→}
 10→
 11→/**
 12→ * Convert Block array to TipTap document JSON.
 13→ * Effects parameter is reserved for future use (Step 13).
 14→ */
 15→export function blocksToTipTapDoc(
 16→  blocks: Block[],
 17→  _effects?: unknown[],
 18→): JSONContent {
 19→  return {
 20→    type: "doc",
 21→    content: blocks.map(blockToNode),
 22→  };
 23→}
 24→
 25→function blockToNode(block: Block): JSONContent {
 26→  switch (block.type) {
 27→    case "paragraph":
 28→      return { type: "paragraph", content: textContent(block.text) };
 29→    case "heading":
 30→      return {
 31→        type: "heading",
 32→        attrs: { level: block.level },
 33→        content: textContent(block.text),
 34→      };
 35→    case "list":
 36→      return {
 37→        type: block.ordered ? "orderedList" : "bulletList",
 38→        content: block.items.map((item) => ({
 39→          type: "listItem",
 40→          content: [{ type: "paragraph", content: textContent(item) }],
 41→        })),
 42→      };
 43→    case "code":
 44→      return {
 45→        type: "codeBlock",
 46→        attrs: { language: block.language },
 47→        content: textContent(block.text),
 48→      };
 49→    case "quote":
 50→      return {
 51→        type: "blockquote",
 52→        content: [{ type: "paragraph", content: textContent(block.text) }],
 53→      };
 54→    case "table":
 55→      return tableToNode(block);
 56→  }
 57→}
 58→
 59→function textContent(text: string): JSONContent[] {
 60→  if (!text) return [];
 61→  return [{ type: "text", text }];
 62→}
 63→
 64→function tableToNode(block: {
 65→  headers: string[];
 66→  rows: string[][];
 67→}): JSONContent {
 68→  const headerRow: JSONContent = {
 69→    type: "tableRow",
 70→    content: block.headers.map((h) => ({
 71→      type: "tableHeader",
 72→      content: [{ type: "paragraph", content: textContent(h) }],
 73→    })),
 74→  };
 75→  const dataRows = block.rows.map((row) => ({
 76→    type: "tableRow",
 77→    content: row.map((cell) => ({
 78→      type: "tableCell",
 79→      content: [{ type: "paragraph", content: textContent(cell) }],
 80→    })),
 81→  }));
 82→  return { type: "table", content: [headerRow, ...dataRows] };
 83→}
 84→
 85→/**
 86→ * Convert TipTap document JSON back to Block array.
 87→ */
 88→export function tipTapDocToBlocks(doc: JSONContent): Block[] {
 89→  if (!doc.content) return [];
 90→  return doc.content.map(nodeToBlock).filter((b): b is Block => b !== null);
 91→}
 92→
 93→function nodeToBlock(node: JSONContent): Block | null {
 94→  switch (node.type) {
 95→    case "paragraph":
 96→      return { type: "paragraph", text: extractText(node) };
 97→    case "heading":
 98→      return {
 99→        type: "heading",
100→        level: (node.attrs?.level as 1 | 2 | 3 | 4 | 5 | 6) ?? 1,
101→        text: extractText(node),
102→      };
103→    case "bulletList":
104→      return { type: "list", ordered: false, items: extractListItems(node) };
105→    case "orderedList":
106→      return { type: "list", ordered: true, items: extractListItems(node) };
107→    case "codeBlock":
108→      return {
109→        type: "code",
110→        language: (node.attrs?.language as string) ?? "text",
111→        text: extractText(node),
112→      };
113→    case "blockquote":
114→      return { type: "quote", text: extractNestedText(node) };
115→    case "table":
116→      return tableNodeToBlock(node);
117→    default:
118→      return null;
119→  }
120→}
121→
122→function extractText(node: JSONContent): string {
123→  if (!node.content) return "";
124→  return node.content.map((c) => c.text ?? "").join("");
125→}
126→
127→function extractNestedText(node: JSONContent): string {
128→  if (!node.content) return "";
129→  return node.content.map((child) => extractText(child)).join("\n");
130→}
131→
132→function extractListItems(node: JSONContent): string[] {
133→  if (!node.content) return [];
134→  return node.content.map((listItem) => {
135→    if (!listItem.content) return "";
136→    // listItem contains paragraph(s)
137→    return listItem.content.map((p) => extractText(p)).join("\n");
138→  });
139→}
140→
141→function tableNodeToBlock(node: JSONContent): Block {
142→  if (!node.content || node.content.length === 0) {
143→    return { type: "table", headers: [], rows: [] };
144→  }
145→  const [headerRow, ...dataRows] = node.content;
146→  const headers = (headerRow?.content ?? []).map((cell) =>
147→    extractNestedText(cell),
148→  );
149→  const rows = dataRows.map((row) =>
150→    (row.content ?? []).map((cell) => extractNestedText(cell)),
151→  );
152→  return { type: "table", headers, rows };
153→}
