import type { Block } from "@chat-exporter/shared";
import { render, screen } from "@testing-library/react";
import { beforeAll, describe, expect, test, vi } from "vitest";
import { TurnEditor } from "../turn-editor";

beforeAll(() => {
  // TipTap/ProseMirror may need clipboard API in jsdom
  if (!navigator.clipboard) {
    Object.defineProperty(navigator, "clipboard", {
      value: { writeText: vi.fn(), readText: vi.fn() },
    });
  }
});

describe("TurnEditor", () => {
  const sampleBlocks: Block[] = [
    { type: "paragraph", text: "Hello World" },
    { type: "heading", level: 2, text: "Test Heading" },
  ];

  test("renders without crashing", () => {
    const { container } = render(
      <TurnEditor blocks={sampleBlocks} editable={true} />,
    );

    expect(container.querySelector(".ProseMirror")).toBeTruthy();
  });

  test("renders block content", () => {
    render(<TurnEditor blocks={sampleBlocks} editable={true} />);

    expect(screen.getByText("Hello World")).toBeTruthy();
    expect(screen.getByText("Test Heading")).toBeTruthy();
  });

  test("renders empty blocks without error", () => {
    const { container } = render(
      <TurnEditor blocks={[]} editable={true} />,
    );

    expect(container.querySelector(".ProseMirror")).toBeTruthy();
  });
});

import type { Block } from "@chat-exporter/shared";
import { EditorContent, useEditor } from "@tiptap/react";
import { useEffect, useRef } from "react";
import { extensions } from "./extensions";
import { blocksToTipTapDoc, tipTapDocToBlocks } from "./serializer";

interface TurnEditorProps {
  blocks: Block[];
  effects?: unknown[];
  editable: boolean;
  onContentChange?: (blocks: Block[]) => void;
}

export function TurnEditor({
  blocks,
  effects,
  editable,
  onContentChange,
}: TurnEditorProps) {
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const editor = useEditor({
    extensions,
    content: blocksToTipTapDoc(blocks, effects),
    editable,
    onUpdate: ({ editor }) => {
      if (!onContentChange) return;

      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }

      debounceRef.current = setTimeout(() => {
        const updatedBlocks = tipTapDocToBlocks(editor.getJSON());
        onContentChange(updatedBlocks);
      }, 500);
    },
  });

  // Sync editable prop
  useEffect(() => {
    if (editor && editor.isEditable !== editable) {
      editor.setEditable(editable);
    }
  }, [editor, editable]);

  // Clean up debounce on unmount
  useEffect(() => {
    return () => {
      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }
    };
  }, []);

  if (!editor) {
    return null;
  }

  return (
    <div className="prose prose-sm max-w-none dark:prose-invert">
      <EditorContent editor={editor} />
    </div>
  );
}

